diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 0afe02fc08ff..b7a81b7ab74e 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14774,6 +14774,31 @@ Value *BoUpSLP::vectorizeTree(
 #endif
       LLVM_DEBUG(dbgs() << "SLP: \tErasing scalar:" << *Scalar << ".\n");
       auto *I = cast<Instruction>(Scalar);
+      // Check if the instruction is used by a phi node in the same basic block
+      // and has external dependencies (not just loop-carried values)
+      bool ShouldSkip = false;
+      for (User *U : Scalar->users()) {
+        if (PHINode *PN = dyn_cast<PHINode>(U)) {
+          if (PN->getParent() == I->getParent()) {
+            // Check if the instruction has operands that are not loop-carried
+            for (Value *Op : I->operands()) {
+              if (Instruction *OpI = dyn_cast<Instruction>(Op)) {
+                if (OpI->getParent() != I->getParent()) {
+                  ShouldSkip = true;
+                  break;
+                }
+              } else if (!isa<Constant>(Op)) {
+                // Non-instruction, non-constant operand (like function argument)
+                ShouldSkip = true;
+                break;
+              }
+            }
+            if (ShouldSkip) break;
+          }
+        }
+      }
+      if (ShouldSkip)
+        continue;
       RemovedInsts.push_back(I);
     }
   }
